const j = $json || {};
let md = '';
if (j.message && j.message.content) { md = j.message.content; }
else if (j.content && j.content[0] && j.content[0].text) { md = j.content[0].text; }
else if (typeof j.markdown === 'string') { md = j.markdown; }
md = md || '';
const top = md.split(/\n/).filter(function(l){ return /adnoc|energy|oil|gas|lng|masdar|taqa/i.test(l); }).slice(0,4).join('; ') || 'UAE and ADNOC energy sector developments';
const style = 'Premium editorial intelligence-report cover. Deep navy (#0A1A2F) background with refined gold (#C9A24B) accents. Abstract professional energy motifs. NO text, NO logos, NO faces.';
return [{ json: { markdown: md || 'No data available for this period.', date: new Date().toISOString().slice(0,10), coverPrompt: style + ' Visual theme inspired by: ' + top } }];

let raw = ($json && $json.markdown) || '';
let data = null;
try { data = JSON.parse(raw); } catch (e) { try { var m = raw.match(/\{[\s\S]*\}/); if (m) data = JSON.parse(m[0]); } catch (e2) { data = null; } }
const date = ($json && $json.date) || new Date().toISOString().slice(0,10);
const fs = require('fs');
function fileUri(base){ var t=[['/config/branding/'+base+'.png','image/png'],['/config/branding/'+base+'.jpg','image/jpeg'],['/config/branding/'+base+'.jpeg','image/jpeg']]; for(var i=0;i<t.length;i++){ try { return 'data:'+t[i][1]+';base64,'+fs.readFileSync(t[i][0]).toString('base64'); } catch(e){} } return ''; }
const cover=fileUri('cover'), banner=fileUri('banner'), avatar=fileUri('jarvis-avatar');
let hero=''; try { var hb=$('Generate Cover (Image Provider)').first().json.data[0].b64_json; if(hb) hero='data:image/png;base64,'+hb; } catch(e){ hero=''; }
function ord(n){ var s=['th','st','nd','rd'], v=n%100; return n+(s[(v-20)%10]||s[v]||s[0]); }
function prettyDate(d){ try { var p=(d||'').split('-'); var dt=new Date(Number(p[0]),Number(p[1])-1,Number(p[2])); var M=['January','February','March','April','May','June','July','August','September','October','November','December']; return M[dt.getMonth()]+' '+ord(dt.getDate())+' '+dt.getFullYear(); } catch(e){ return d; } }
const dateStr=prettyDate(date), weekOf=(data&&data.weekOf)?data.weekOf:dateStr;
function esc(s){ return (s==null?'':String(s)).replace(/[&<>]/g,function(c){return({'&':'&amp;','<':'&lt;','>':'&gt;'})[c];}); }
function riskColor(r){ r=(r||'').toString().toLowerCase(); if(r.indexOf('high')===0)return '#B02525'; if(r.indexOf('med')===0)return '#B8860B'; if(r.indexOf('low')===0)return '#1E8E5A'; return '#5A6472'; }

var BCSS='*{box-sizing:border-box} body{margin:0;font-family:-apple-system,"Segoe UI",Arial,sans-serif;color:#11151c;font-size:14px;line-height:1.55} '
 + '.wrap{padding:22px 40px 10px} '
 + '.lead{font-size:16px;line-height:1.75;margin:0 0 4px} .lead .dc{float:left;font-family:Georgia,serif;font-size:56px;line-height:44px;padding:6px 12px 0 0;color:#2E9BE6;font-weight:700} '
 + '.callout{background:#EAF4FC;border-left:4px solid #2E9BE6;padding:12px 16px;margin:18px 0;font-size:14px} '
 + '.sec{page-break-before:always} .sec.first{page-break-before:avoid} '
 + 'h2.h{font-family:Georgia,serif;font-size:21px;color:#0A1A2F;margin:6px 0 12px;padding-bottom:8px;border-bottom:2px solid #0A1A2F} '
 + 'h2.h .kick{display:block;font-family:Arial;font-size:10.5px;letter-spacing:2px;color:#2E9BE6;text-transform:uppercase;margin-bottom:3px;font-weight:700} '
 + '.feature{border:1px solid #E2E6EC;border-radius:8px;overflow:hidden;margin:16px 0;page-break-inside:avoid} '
 + '.feature .ph{height:200px;background-size:cover;background-position:center;background-color:#0A1A2F} .feature .fb{padding:14px 18px} '
 + '.feature h3{font-family:Georgia,serif;font-size:19px;color:#0A1A2F;margin:0 0 7px;line-height:1.3} .feature p{margin:0 0 9px;font-size:14px;line-height:1.62;color:#2b3340} .feature a{color:#2E9BE6;text-decoration:none;font-size:12.5px;font-weight:700} '
 + '.co{border:1px solid #E2E6EC;border-radius:8px;margin:14px 0;page-break-inside:avoid;overflow:hidden} .co .hd{background:#0A1A2F;color:#fff;padding:9px 14px;font-family:Georgia,serif;font-size:16px;font-weight:700} .co .bd{padding:8px 16px} .co .row{margin:7px 0;font-size:13.5px;line-height:1.5} .co .row .lab{display:inline-block;min-width:128px;padding-right:10px;color:#0A1A2F;font-weight:700;vertical-align:top} '
 + 'table.mv{width:100%;border-collapse:collapse;font-size:13px;margin:8px 0} table.mv th{background:#0A1A2F;color:#fff;text-align:left;padding:8px;font-size:11.5px} table.mv td{padding:8px;border-bottom:1px solid #E2E6EC;vertical-align:top} table.mv tr:nth-child(even) td{background:#F4F6F9} '
 + '.bonus p{font-size:14px;line-height:1.72;margin:0 0 10px} .endbanner{margin-top:26px} .endbanner img{width:100%;display:block} ';

function secH(kick,title,first){ return '<div class="sec'+(first?' first':'')+'"><h2 class="h"><span class="kick">'+esc(kick)+'</span>'+esc(title)+'</h2>'; }
function lead(t){ t=(t||'').toString(); if(!t)return''; return '<p class="lead"><span class="dc">'+esc(t.charAt(0))+'</span>'+esc(t.slice(1))+'</p>'; }
function feature(s){ var im=(s.image||'').toString(); var ph=(/^https?:\/\//.test(im)||im.indexOf('data:')===0)?'<div class="ph" style="background-image:url('+im+')"></div>':''; var src=(s.source||'').toString(); var link=/^https?:\/\//.test(src)?'<a href="'+src+'">Read the source &rsaquo;</a>':(src?'<span style="color:#5A6472;font-size:12.5px">Source: '+esc(src)+'</span>':''); return '<div class="feature">'+ph+'<div class="fb"><h3>'+esc(s.headline)+'</h3><p>'+esc(s.story)+'</p>'+link+'</div></div>'; }
function co(r){ function row(l,v,c){ if(v==null||v==='')v='Not specified'; var x=c?('<span style="color:'+c+';font-weight:700">'+esc(v)+'</span>'):esc(v); return '<div class="row"><span class="lab">'+l+'</span>'+x+'</div>'; } return '<div class="co"><div class="hd">'+esc(r.company)+'</div><div class="bd">'+row('Key Development',r.development)+row('Strategic Theme',r.theme)+row('What It Signals',r.signals)+row('Market Impact / Risk',r.risk,riskColor(r.risk))+row('Watch Point',r.watch)+'</div></div>'; }
function movers(rows){ if(!rows||!rows.length)return '<p style="color:#5A6472">No notable leadership changes this period.</p>'; var h='<tr>'+['Company','Individual','Previous role','New role','Effective','Why it matters'].map(function(x){return '<th>'+x+'</th>';}).join('')+'</tr>'; var b=rows.map(function(r){return '<tr><td><b>'+esc(r.company)+'</b></td><td>'+esc(r.individual)+'</td><td>'+esc(r.previous)+'</td><td>'+esc(r.current)+'</td><td>'+esc(r.date)+'</td><td>'+esc(r.why)+'</td></tr>';}).join(''); return '<table class="mv">'+h+b+'</table>'; }

function bodyInner(){
  if(!data){ return '<div class="wrap"><div class="callout" style="background:#FDECEC;border-color:#B02525">The analyst did not return structured data this run. Raw output below.</div><pre style="white-space:pre-wrap;font-size:12px">'+esc(raw)+'</pre></div>'; }
  var bonus=data.bonus||{}, feats=data.featured||[], noc=data.noc||[], ioc=data.ioc||[];
  var endbanner=banner?('<div class="endbanner"><img src="'+banner+'"/></div>'):'';
  var signoff=avatar?('<div style="text-align:center;padding:22px 0 6px;border-top:3px solid #2E9BE6;margin-top:22px"><img src="'+avatar+'" style="width:96px;height:96px;border-radius:50%;border:2px solid #2E9BE6"/><div style="font-family:Georgia,serif;color:#0A1A2F;margin-top:8px;font-size:14px">Jarvis — AI News Reporter</div></div>'):'';
  var h='<div class="wrap">';
  h+='<div class="sec first">'+lead(data.intro)+(data.weekOverWeek?('<div class="callout"><b>What changed since last edition:</b> '+esc(data.weekOverWeek)+'</div>'):'')+'</div>';
  if(feats.length){ h+=secH('In focus','Featured Stories')+feats.map(feature).join('')+'</div>'; }
  h+=secH('Regional','Middle East NOCs')+noc.map(co).join('')+'</div>';
  h+=secH('Global','Supermajor IOCs')+ioc.map(co).join('')+'</div>';
  h+=secH('People','Movers & Shakers')+movers(data.movers)+'</div>';
  h+=secH('Analysis','Bonus Read'+(bonus.title?': '+esc(bonus.title):''))+'<div class="bonus">'+(bonus.body?esc(bonus.body).split('\n').map(function(p){return '<p>'+p+'</p>';}).join(''):'')+'</div>'+signoff+endbanner+'</div>';
  h+='</div>'; return h;
}

var coverCSS='*{margin:0}@page{margin:0} html,body{height:100%} .cover{height:100vh;background:#0A1A2F url('+cover+') center/contain no-repeat;position:relative} .cover .date{position:absolute;top:24px;right:30px;color:#fff;font-family:Georgia,serif;font-size:23px;font-weight:700;text-shadow:0 2px 6px rgba(0,0,0,.8)}';
