  var s = (a.contentSnippet||a.content||'').toString().replace(/\s+/g,' ').slice(0,220);
  var u = (a.link||a.url||'').toString();
  return '- ' + t + ' — ' + s + ' (' + u + ')';
});
const text = lines.length ? lines.join('\n') : 'No leadership-change articles retrieved.';
return [{ json: { moversDigest: text, moversCount: arts.length } }];

const r = $('Render HTML').first().json;
